-/// Look for patterns like
+/// Fold the pattern:
+///   %cmp1 = icmp sgt T %a, -1          ; a > -1 (i.e., a >= 0)
+///   %inner = select i1 %other_cond, i1 %cmp1, i1 false
+///   %cmp2 = icmp slt T %a, C           ; a < C (signed)
+///   %outer = select i1 %inner, i1 %cmp2, i1 false
+/// Into:
+///   %new_cmp = icmp ult T %a, C        ; a <u C (equivalent when a >= 0)
+///   %outer = select i1 %other_cond, i1 %new_cmp, i1 false
+///
+/// This combines the range check (a >= 0 && a < C) into a single unsigned
+/// comparison when the lower bound is known to be 0.
+static Instruction *foldSelectOfICmpRangeCheck(SelectInst &SI,
+                                               InstCombiner::BuilderTy &Builder) {
+  Value *CondVal = SI.getCondition();
+  Value *TrueVal = SI.getTrueValue();
+  Value *FalseVal = SI.getFalseValue();
+
+  // The outer select's false value must be false (logical AND pattern)
+  if (!match(FalseVal, m_Zero()))
+    return nullptr;
+
+  // The outer select's condition must be a select
+  auto *InnerSel = dyn_cast<SelectInst>(CondVal);
+  if (!InnerSel)
+    return nullptr;
+
+  // The inner select's false value must also be false (logical AND pattern)
+  if (!match(InnerSel->getFalseValue(), m_Zero()))
+    return nullptr;
+
+  // Both selects must have one use for profitability
+  if (!InnerSel->hasOneUse() || !SI.hasOneUse())
+    return nullptr;
+
+  // The outer select's true value must be an icmp
+  auto *Cmp2 = dyn_cast<ICmpInst>(TrueVal);
+  if (!Cmp2)
+    return nullptr;
+
+  // The inner select's true value must be an icmp
+  auto *Cmp1 = dyn_cast<ICmpInst>(InnerSel->getTrueValue());
+  if (!Cmp1)
+    return nullptr;
+
+  // Both icmps must compare the same variable
+  Value *Var1 = Cmp1->getOperand(0);
+  Value *Var2 = Cmp2->getOperand(0);
+  if (Var1 != Var2)
+    return nullptr;
+
+  // Cmp1 must be: icmp sgt Var, -1 (i.e., Var > -1, meaning Var >= 0)
+  const APInt *C1;
+  if (Cmp1->getPredicate() != ICmpInst::ICMP_SGT ||
+      !match(Cmp1->getOperand(1), m_APInt(C1)) ||
+      !C1->isAllOnes())
+    return nullptr;
+
+  // Cmp2 must be: icmp slt Var, C (i.e., Var < C, signed)
+  const APInt *C2;
+  if (Cmp2->getPredicate() != ICmpInst::ICMP_SLT ||
+      !match(Cmp2->getOperand(1), m_APInt(C2)))
+    return nullptr;
+
+  // C2 must be positive (so that Var >= 0 && Var < C2 is equivalent to Var <u C2)
+  if (C2->isNegative())
+    return nullptr;
+
+  // Create the new unsigned comparison: icmp ult Var, C2
+  Value *NewCmp = Builder.CreateICmpULT(Var1, Cmp2->getOperand(1),
+                                        Cmp2->getName());
+
+  // Create the new select: select other_cond, new_cmp, false
+  auto *NewSel = SelectInst::Create(InnerSel->getCondition(), NewCmp, FalseVal,
+                                    SI.getName());
+  NewSel->copyMetadata(SI);
+  return NewSel;
+}
